const char *pci_vendor_name(uint16 vendor_id) {
    for (uint32 i = 0; pci_vendors[i].name; i++)
        if (pci_vendors[i].id == vendor_id) return pci_vendors[i].name;
    return 0;
}

const char *pci_class_name(uint8 cls, uint8 sub) {
    // First try exact (cls, sub) match
    for (uint32 i = 0; pci_classes[i].name; i++)
        if (pci_classes[i].cls == cls && pci_classes[i].sub == sub)
            return pci_classes[i].name;
    // Fall back to class-only match (sub == 0xFF)
    for (uint32 i = 0; pci_classes[i].name; i++)
        if (pci_classes[i].cls == cls && pci_classes[i].sub == 0xFF)
            return pci_classes[i].name;
    return 0;
}
